import * as echarts from 'echarts';
import request from '@/utils/request';
export default {
  name: "Home",
  data() {
    return {
      config: {
        systemName: "无人机管理系统V1.0",
        inspectFreq: 30,
        logRetention: 90,
        maxHeight: 120,
        maxBattery: 45,
        alertThreshold: 5
      },
      detailDialogVisible: false,
      // 详情弹窗开关
      currentQuarter: "",
      // 当前点击的季度
      quarterDetailData: {
        // 季度详情模拟数据
        "第一季度": [20, 25, 30],
        "第二季度": [30, 40, 58],
        "第三季度": [25, 35, 36],
        "第四季度": [40, 50, 55]
      }
    };
  },
  methods: {
    async initCharts() {
      const taskData = [85, 128, 96, 145];
      const errorData = [12, 8, 15, 7];
      const quarters = ['第一季度', '第二季度', '第三季度', '第四季度'];

      // 1. 柱状图（执行任务数）- 交互：悬停高亮+点击下钻
      const barChart = echarts.init(document.getElementById('bar'));
      const barOption = {
        title: {
          text: '各季度无人机执行任务数',
          textStyle: {
            fontSize: 16
          }
        },
        tooltip: {
          trigger: 'axis',
          formatter: params => {
            const item = params[0];
            return `
              <div style="padding: 5px;">
                <div>${item.name}</div>
                <div style="color: ${item.color};">执行任务数：${item.value} 次</div>
                <div>同比增长：${Math.round(Math.random() * 20)}%</div>
              </div>
            `; // 自定义 tooltip 内容
          }
        },
        legend: {
          data: ['执行任务数'],
          right: 20
        },
        xAxis: {
          type: 'category',
          data: quarters,
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          }
        },
        yAxis: {
          type: 'value',
          name: '任务数（次）',
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          },
          splitLine: {
            lineStyle: {
              type: 'dashed',
              color: '#eee'
            }
          }
        },
        series: [{
          name: '执行任务数',
          data: taskData,
          type: 'bar',
          itemStyle: {
            color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [{
              offset: 0,
              color: '#4299E1'
            }, {
              offset: 1,
              color: '#2B6CB0'
            }]) // 渐变填充
          },
          emphasis: {
            itemStyle: {
              color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [{
                offset: 0,
                color: '#66B1FF'
              }, {
                offset: 1,
                color: '#337ECC'
              }]),
              shadowBlur: 10,
              shadowColor: 'rgba(0,0,0,0.3)' // 悬停阴影
            }
          }
        }]
      };
      barChart.setOption(barOption);

      // 点击柱状图 - 打开详情弹窗
      barChart.on('click', params => {
        this.currentQuarter = params.name;
        this.detailDialogVisible = true;
        this.initDetailChart(); // 初始化详情图表
      });

      // 2. 折线图（异常次数）- 交互：图例切换+区域高亮
      const lineChart = echarts.init(document.getElementById('line'));
      const lineOption = {
        title: {
          text: '各季度无人机异常次数',
          textStyle: {
            fontSize: 16
          }
        },
        tooltip: {
          trigger: 'axis',
          axisPointer: {
            type: 'shadow'
          } // 坐标轴指示器
        },
        legend: {
          data: ['异常次数', '预警阈值'],
          right: 20
        },
        xAxis: {
          type: 'category',
          data: quarters,
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          }
        },
        yAxis: {
          type: 'value',
          name: '次数（次）',
          axisLine: {
            lineStyle: {
              color: '#999'
            }
          },
          splitLine: {
            lineStyle: {
              type: 'dashed',
              color: '#eee'
            }
          },
          markLine: {
            // 预警阈值参考线
            data: [{
              name: '预警阈值',
              yAxis: this.config.alertThreshold,
              lineStyle: {
                type: 'dashed',
                color: '#F56C6C'
              }
            }]
          }
        },
        series: [{
          name: '异常次数',
          data: errorData,
          type: 'line',
          smooth: true,
          lineStyle: {
            width: 3,
            color: '#4299E1'
          },
          itemStyle: {
            color: '#2B6CB0',
            borderWidth: 2,
            borderColor: '#fff'
          },
          areaStyle: {
            color: new echarts.graphic.LinearGradient(0, 0, 0, 1, [{
              offset: 0,
              color: 'rgba(66, 153, 225, 0.5)'
            }, {
              offset: 1,
              color: 'rgba(66, 153, 225, 0.1)'
            }])
          },
          emphasis: {
            lineStyle: {
              width: 4
            },
            itemStyle: {
              color: '#66B1FF',
              shadowBlur: 10
            }
          }
        }, {
          name: '预警阈值',
          type: 'line',
          data: [this.config.alertThreshold, this.config.alertThreshold, this.config.alertThreshold, this.config.alertThreshold],
          lineStyle: {
            type: 'dashed',
            color: '#F56C6C'
          },
          symbol: 'none'
        }]
      };
      lineChart.setOption(lineOption);

      // 3. 窗口自适应
      window.addEventListener('resize', () => {
        barChart.resize();
        lineChart.resize();
        if (this.detailDialogVisible) this.initDetailChart();
      });
    },
    // 详情图表（数据下钻）
    initDetailChart() {
      const detailChart = echarts.init(document.getElementById('detailChart'));
      const detailOption = {
        title: {
          text: `${this.currentQuarter} 任务类型分布`,
          textStyle: {
            fontSize: 16
          }
        },
        tooltip: {
          trigger: 'item',
          formatter: '{b}: {c} 次 ({d}%)'
        },
        legend: {
          orient: 'vertical',
          left: 10,
          data: ['巡逻任务', '巡检任务', '应急任务']
        },
        series: [{
          type: 'pie',
          radius: ['40%', '70%'],
          center: ['50%', '50%'],
          data: [{
            name: '巡逻任务',
            value: this.quarterDetailData[this.currentQuarter][0]
          }, {
            name: '巡检任务',
            value: this.quarterDetailData[this.currentQuarter][1]
          }, {
            name: '应急任务',
            value: this.quarterDetailData[this.currentQuarter][2]
          }],
          itemStyle: {
            color: params => {
              const colors = ['#4299E1', '#67C21A', '#F56C6C'];
              return colors[params.dataIndex];
            },
            emphasis: {
              shadowBlur: 10,
              shadowColor: 'rgba(0,0,0,0.3)'
            }
          },
          label: {
            show: false
          },
          labelLine: {
            show: false
          }
        }]
      };
      detailChart.setOption(detailOption);
    }
  },
  mounted() {
    this.initCharts();
  }
};
